import{c as e,Q as s,j as a,m as d}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Архитектура и среда выполнения","description":"","frontmatter":{},"headers":[],"relativePath":"ru/architecture.md","filePath":"ru/architecture.md","lastUpdated":1780001723000}'),o={name:"ru/architecture.md"};function l(c,i,t,n,p,h){return s(),a("div",null,[...i[0]||(i[0]=[d(`<h1 id="архитектура-и-среда-выполнения" tabindex="-1">Архитектура и среда выполнения <a class="header-anchor" href="#архитектура-и-среда-выполнения" aria-label="Permalink to &quot;Архитектура и среда выполнения&quot;">​</a></h1><p>Эта страница описывает backend, frontend, зависимости среды выполнения и поведение логирования.</p><h2 id="архитектура" tabindex="-1">Архитектура <a class="header-anchor" href="#архитектура" aria-label="Permalink to &quot;Архитектура&quot;">​</a></h2><p>Пакет backend находится в <code>src/dj_track_similarity/</code>.</p><ul><li><code>cli.py</code> предоставляет Typer CLI <code>dj-sim</code>.</li><li><code>api.py</code> создаёт приложение FastAPI и REST-эндпоинты.</li><li><code>database.py</code> отвечает за доступ к SQLite и все изменения базы данных.</li><li><code>db_schema.py</code> определяет текущую схему SQLite и её проверку.</li><li><code>scanner.py</code> сканирует папки и читает метаданные Mutagen.</li><li><code>scan_jobs.py</code>, <code>analysis_jobs.py</code>, <code>sonara_jobs.py</code>, <code>genre_jobs.py</code>, <code>classifier_jobs.py</code> и <code>tags.py</code> управляют отменяемыми заданиями и объектами статуса.</li><li><code>audio_loader.py</code> предоставляет общую загрузку аудио по принципу native-first.</li><li><code>sonara_features.py</code> извлекает сфокусированный набор признаков плейлиста Sonara.</li><li><code>sonara_similarity.py</code> и <code>sonara_similarity_scoring.py</code> ранжируют похожесть признаков Sonara.</li><li><code>embedding.py</code> содержит адаптеры embedding для MERT и CLAP.</li><li><code>genres.py</code> содержит жанровый адаптер MAEST.</li><li><code>classifier_scoring.py</code> загружает продвинутые артефакты классификаторов и оценивает треки с полным набором признаков.</li><li><code>tags.py</code> записывает метки MAEST в стандартное поле жанра и выполняет отменяемое задание записи жанровых тегов; <code>wave_tags.py</code> предоставляет защищённый путь записи жанра для WAV/ID3.</li><li><code>search.py</code> выполняет поиск похожести в пространстве embedding.</li><li><code>exporter.py</code> пишет выходные файлы M3U и CSV.</li><li><code>runtime.py</code> выбирает <code>auto</code>, <code>cpu</code> или <code>cuda</code> для задач PyTorch.</li><li><code>dependencies.py</code> проверяет зависимости среды выполнения, например <code>ffmpeg</code>.</li><li><code>logging_config.py</code> настраивает ротируемые файловые логи.</li></ul><p>Frontend находится в <code>frontend/src/</code>.</p><ul><li><code>api.ts</code> зеркалит контракт FastAPI.</li><li><code>App.tsx</code> координирует состояние приложения и рабочие процессы.</li><li><code>LibraryPanel.tsx</code> содержит элементы управления сканированием, обновлением, анализом, сбросом и очисткой.</li><li><code>TrackPanel.tsx</code>, <code>TrackRows.tsx</code> и <code>TrackMetadataDialog.tsx</code> показывают строки библиотеки, элементы управления понравившимися треками и подробности трека.</li><li><code>SearchPlaylistPanel.tsx</code> содержит вкладки SONARA, MERT, CLAP и CLASS, а также элементы управления экспортом.</li></ul><h2 id="зависимости-среды-выполнения" tabindex="-1">Зависимости среды выполнения <a class="header-anchor" href="#зависимости-среды-выполнения" aria-label="Permalink to &quot;Зависимости среды выполнения&quot;">​</a></h2><p>Основные зависимости среды выполнения объявлены в <code>pyproject.toml</code>:</p><ul><li><code>numpy&gt;=1.26,&lt;2.0</code></li><li><code>mutagen</code></li><li><code>pydantic</code></li><li><code>typer</code></li><li><code>fastapi</code></li><li><code>uvicorn</code></li><li><code>joblib</code></li></ul><p>Дополнительные группы зависимостей:</p><ul><li><code>sonara</code>: устанавливает поддержку Sonara.</li><li><code>ml</code>: устанавливает синхронизированный стек PyTorch/Torchaudio/Torchvision/TorchCodec, Transformers, Hugging Face Hub, LAION-CLAP и поддержку MAEST.</li><li><code>rhythm-lab</code>: устанавливает scikit-learn для локального обучения и бенчмаркинга классификаторов в Rhythm Lab.</li><li><code>dev</code>: устанавливает pytest и Ruff.</li></ul><p><code>ffmpeg</code> требуется для надёжного запуска сервера и декодирования аудио. Он может находиться через <code>PATH</code> или задаваться переменной:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DJ_TRACK_SIMILARITY_FFMPEG</span></span></code></pre></div><p>Проверенный стек Windows CUDA:</p><ul><li>PyTorch <code>2.11.0</code></li><li>Torchaudio <code>2.11.0</code></li><li>Torchvision <code>0.26.0</code></li><li>TorchCodec <code>0.13.0</code></li><li>NumPy <code>&gt;=1.26,&lt;2.0</code></li><li>Индекс wheel-пакетов PyTorch <code>https://download.pytorch.org/whl/cu130</code></li></ul><p>Установите соответствующие CUDA-wheel из официального индекса wheel-пакетов PyTorch перед установкой остальных ML-зависимостей:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install torch</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torchvision</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.26</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torchaudio</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">url https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">download.pytorch.org</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cu130</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install torchcodec</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.13</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">url https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">download.pytorch.org</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cu130</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;.[sonara,ml,dev]&quot;</span></span></code></pre></div><p>Используйте <code>.[sonara,ml,rhythm-lab,dev]</code>, если та же среда будет также обучать профили классификаторов Rhythm Lab.</p><p>На Windows декодирование Torchaudio через TorchCodec требует shared-сборки FFmpeg с DLL, доступными в <code>PATH</code>, а не только статического <code>ffmpeg.exe</code>. Настройка портативных инструментов должна использовать GyanD <code>ffmpeg 8.1.1-full_build-shared</code> или совместимую раскладку <code>full_build-shared</code>, например:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\ffmpeg.exe</span></span>
<span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\avcodec-*.dll</span></span>
<span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\avformat-*.dll</span></span></code></pre></div><h2 id="логирование" tabindex="-1">Логирование <a class="header-anchor" href="#логирование" aria-label="Permalink to &quot;Логирование&quot;">​</a></h2><p>Файловое логирование среды выполнения по умолчанию пишет в:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dj-track-similarity.log</span></span></code></pre></div><p>Лог ротируется ежедневно в полночь и хранит один ротированный день. По умолчанию записываются сводки уровня INFO: запуск, завершение, предупреждения и ошибки. Успешные события заданий по отдельным трекам агрегируются и не пишутся в файловый лог, если не включено подробное логирование.</p><p>Переменные окружения:</p><ul><li><code>DJ_TRACK_SIMILARITY_LOG</code>: путь к файловому логу.</li><li><code>DJ_TRACK_SIMILARITY_LOG_LEVEL</code>: <code>debug</code>, <code>info</code>, <code>warning</code>, <code>error</code> или <code>critical</code>.</li><li><code>DJ_TRACK_SIMILARITY_LOG_TRACK_EVENTS</code>: установите в <code>1</code>, <code>true</code>, <code>yes</code> или <code>on</code>, чтобы записывать успешные события заданий по отдельным трекам.</li></ul><p>Сервер также поддерживает <code>--log-level</code> и <code>--log-track-events</code>.</p><p>Команды анализа CLI во время работы печатают живой однострочный индикатор прогресса. Строка перерисовывается на месте и включает индикатор прогресса, процент выполнения, <code>processed/total</code>, <code>analyzed</code>, <code>failed</code>, приблизительный <code>tracks/s</code> и оценку оставшегося времени. Это прогресс только для консоли того процесса CLI, который запустил задание; он не подключается к заданиям, запущенным из web UI или процесса сервера.</p><p>Команды анализа CLI могут также записывать строки диагностического тайминга в файловый лог, если в команде передан <code>--diagnostics</code> или установлено <code>DJ_TRACK_SIMILARITY_ANALYSIS_DIAGNOSTICS=1</code>. Они включают на уровне пакета <code>prepare_seconds</code>, <code>decode_seconds</code>, <code>inference_seconds</code>, <code>save_seconds</code>, <code>total_seconds</code>, <code>tracks_per_second</code>, число треков и число окон для MERT/CLAP и MAEST. Диагностика Sonara логирует <code>total_seconds</code> и <code>tracks_per_second</code> по отдельным трекам, поскольку её внутреннее декодирование и извлечение признаков выполняются внутри Sonara. Загрузка аудио также логирует подробности переключения декодеров по пути: неудавшиеся декодеры вроде <code>torchaudio</code>, <code>wave</code> или <code>ffmpeg</code>, текст их ошибок и резервный декодер, который в итоге сработал, если такой нашёлся. Это диагностическое логирование по умолчанию выключено.</p>`,30)])])}const g=e(o,[["render",l]]);export{k as __pageData,g as default};
